  ('medical-tech-moex-09681', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '以血清學檢驗（serologic diagnosis）偵測病毒專一性抗體，一般需要兩次採檢，一次在急性期（acute phase），一次在恢復 期（convalescent phase），但下列何種檢測通常一次急性期採檢，就足已確認是急性期感染？', '["中和試驗（neutralization test, NT）", "偵測病毒專一性的IgM", "血球凝集抑制試驗（hemagglutination inhibition test, HI）", "補體固定試驗（complement fixation test, CF）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 56, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09682', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '血球凝集試驗（hemagglutination test, HA），一般於低溫進行（4℃～22℃），但下列何種病毒可在37℃進行反應？', '["A型流感病毒（influenza A virus）", "B型流感病毒（influenza B virus）", "麻疹病毒（measles virus）", "副流感病毒（parainfluenza virus）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 57, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09683', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何者抗病毒藥物不是蛋白酶抑制劑（protease inhibitor）？', '["saquinavir", "raltegravir", "lopinavir", "darunavir"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 58, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09684', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列對抗病毒藥物acyclovir的敘述，何者錯誤？', '["可用來治療單純疱疹病毒", "其藥物需要經由病毒蛋白酶（protease）切割後才能發揮作用", "主要是抑制病毒DNA聚合酶（DNA polymerase）作用", "病毒的thymidine kinase基因突變可能會導致病毒對acyclovir產生抗藥性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 59, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09685', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關沙賓（Sabin）及沙克（Salk）疫苗之敘述，何者錯誤？', '["沙賓疫苗是活性減毒口服小兒麻痹疫苗", "沙克疫苗是去活性小兒麻痹疫苗", "沙克疫苗之施打可以造成群體免疫", "沙賓疫苗可誘發IgA抗體產生"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 60, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
