  ('medical-tech-moex-09687', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於以聚合酶連鎖反應（PCR）進行呼吸道病毒的快速分子檢測，下列敘述何者錯誤？', '["若檢測對象為病毒之RNA則需要加上反轉錄（reverse transcription, RT）前步驟", "可以設計多對專一序列之引子建立檢測多重病毒之平台（multiplex PCR）", "可以應用real-time PCR技術縮短檢測時間", "可以用來區分A型或B型流感病毒，但無法進一步用此方法區分A型流感病毒之亞型（subtypes）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
